const fs = require('fs');

const GITHUB_MAP = {
  'portainer/portainer-ee': { name: 'Portainer', github: 'portainer/portainer' },
  'portainer/portainer-ce': { name: 'Portainer', github: 'portainer/portainer' },
  'mintplexlabs/anythingllm': { name: 'AnythingLLM', github: 'Mintplex-Labs/anything-llm' },
  'n8nio/n8n': { name: 'n8n', github: 'n8n-io/n8n' },
  'searxng/searxng': { name: 'SearXNG', github: 'searxng/searxng', githubFallback: 'commits' },
  'caddy': { name: 'Caddy', github: 'caddyserver/caddy' },
  'amir20/dozzle': { name: 'Dozzle', github: 'amir20/dozzle' },
  'vllm/vllm-openai': { name: 'vLLM', github: 'vllm-project/vllm' },
  'pgvector/pgvector': { name: 'pgvector', github: 'pgvector/pgvector' },
  'flowiseai/flowise': { name: 'Flowise', github: 'FlowiseAI/Flowise' },
  'onerahmet/openai-whisper-asr-webservice': { name: 'Whisper', github: 'ahmetoner/whisper-asr-webservice' },
  'ghcr.io/paperless-ngx/paperless-ngx': { name: 'Paperless', github: 'paperless-ngx/paperless-ngx' },
  'mattermost/mattermost-team-edition': { name: 'Mattermost', github: 'mattermost/mattermost' },
};

function loadImagesFromCompose() {
  // Liest die tatsaechlich gepinnten Image-Tags live aus docker-compose.yml
  // (read-only gemountet unter /data/docker-compose.yml) -- KEINE gepflegte
  // Kopie mehr, die nach jedem Upgrade von Hand nachgezogen werden muesste.
  // Auskommentierte Services (z.B. "# image: ...") werden automatisch uebersprungen,
  // da die Zeile dann nicht mit Leerzeichen beginnt.
  const compose = fs.readFileSync('/data/docker-compose.yml', 'utf8');
  const images = [];
  const seen = new Set();
  for (const line of compose.split('\n')) {
    const m = line.match(/^\s+image:\s+(.+)$/);
    if (!m) continue;
    const imageStr = m[1].trim();
    const colon = imageStr.lastIndexOf(':');
    const fullRepo = colon > 0 ? imageStr.slice(0, colon) : imageStr;
    const tag = colon > 0 ? imageStr.slice(colon + 1) : 'latest';
    const baseRepo = fullRepo.replace(/^library\//, '');
    const mapKey = Object.keys(GITHUB_MAP).find(k => baseRepo === k || baseRepo.startsWith(k));
    if (!mapKey || seen.has(fullRepo)) continue;
    seen.add(fullRepo);
    const meta = GITHUB_MAP[mapKey];
    const hubRepo = fullRepo.includes('/') ? fullRepo : `library/${fullRepo}`;
    images.push({ name: meta.name, repo: hubRepo, tag, github: meta.github, githubFallback: meta.githubFallback });
  }
  return images;
}

const IMAGES = loadImagesFromCompose();

function parseSemver(t) {
  const m = /^v?(\d+)\.(\d+)(?:\.(\d+))?/.exec(t || '');
  if (!m) return null;
  return [parseInt(m[1], 10), parseInt(m[2], 10), m[3] ? parseInt(m[3], 10) : 0];
}
function cmpSemver(a, b) {
  for (let i = 0; i < 3; i++) { if (a[i] !== b[i]) return a[i] - b[i]; }
  return 0;
}

const store = $getWorkflowStaticData('global');
if (!store.docker_digests) store.docker_digests = {};

const updates = [];
const checked = [];

for (const img of IMAGES) {
  let digestChanged = false;
  let newerVersion = null;

  try {
    const url = 'https://hub.docker.com/v2/repositories/' + img.repo + '/tags/' + img.tag;
    const res = await this.helpers.httpRequest({ method: 'GET', url, timeout: 10000 });
    const digest = res.digest || res.images?.[0]?.digest || res.last_updated || null;
    const key = img.repo + ':' + img.tag;
    const stored = store.docker_digests[key];
    if (digest) {
      if (stored && stored !== digest) digestChanged = true;
      store.docker_digests[key] = digest;
    }
  } catch (e) {
    checked.push({ name: img.name, status: 'Digest-Fehler: ' + e.message });
    continue;
  }

  const pinned = parseSemver(img.tag);
  if (pinned) {
    try {
      const tagsRes = await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://hub.docker.com/v2/repositories/' + img.repo + '/tags?page_size=100&ordering=last_updated',
        timeout: 15000
      });
      let best = null;
      for (const r of (tagsRes.results || [])) {
        const v = parseSemver(r.name);
        if (v && cmpSemver(v, pinned) > 0 && (!best || cmpSemver(v, best) > 0)) best = v;
      }
      if (best) newerVersion = best.join('.');
    } catch (e) {
      checked.push({ name: img.name, status: 'Versions-Fehler: ' + e.message });
    }
  }

  if (digestChanged || newerVersion) {
    updates.push({ ...img, newerVersion, reason: digestChanged && newerVersion ? 'digest+version' : (digestChanged ? 'digest' : 'version') });
  }
  checked.push({ name: img.name, tag: img.tag, newerVersion: newerVersion || '–', status: newerVersion ? 'NEUE VERSION' : (digestChanged ? 'DIGEST GEAENDERT' : 'aktuell') });
}

return [{ json: { updates, count: updates.length, checked } }];

const { updates } = $input.first().json;
const result = [];

for (const img of updates) {
  let notes = 'Keine Changelog-Informationen verfügbar.';
  let latestTag = '–';

  if (img.changelogUrl) {
    notes = `Release Notes: ${img.changelogUrl}`;
    latestTag = img.tag;
  } else if (img.github) {
    try {
      const releases = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://api.github.com/repos/${img.github}/releases?per_page=5`,
        headers: { 'User-Agent': 'FreiKI-n8n/1.0', 'Accept': 'application/vnd.github.v3+json' },
        timeout: 10000
      });

      if (Array.isArray(releases) && releases.length > 0) {
        latestTag = img.newerVersion || releases[0].tag_name || '–';
        notes = releases.slice(0, 3).map(r => {
          const date = r.published_at?.slice(0, 10) || '?';
          const body = (r.body || 'Keine Release Notes')
            .replace(/<!--.*?-->/gs, '').replace(/#{1,6}\s/g, '').trim().slice(0, 800);
          return `Version ${r.tag_name} (${date}):\n${body}`;
        }).join('\n\n---\n\n');

      } else if (img.githubFallback === 'commits') {
        const commits = await this.helpers.httpRequest({
          method: 'GET',
          url: `https://api.github.com/repos/${img.github}/commits?per_page=10`,
          headers: { 'User-Agent': 'FreiKI-n8n/1.0', 'Accept': 'application/vnd.github.v3+json' },
          timeout: 10000
        });
        const tags = await this.helpers.httpRequest({
          method: 'GET',
          url: `https://api.github.com/repos/${img.github}/tags?per_page=1`,
          headers: { 'User-Agent': 'FreiKI-n8n/1.0', 'Accept': 'application/vnd.github.v3+json' },
          timeout: 10000
        });
        latestTag = tags[0]?.name || '–';
        if (Array.isArray(commits) && commits.length > 0) {
          notes = 'Letzte Änderungen (Commits):\n' + commits.map(c => {
            const date = c.commit.author?.date?.slice(0, 10) || '?';
            const msg = c.commit.message.split('\n')[0].slice(0, 120);
            return `• ${date}: ${msg}`;
          }).join('\n');
        }
      }
    } catch(e) {
      notes = `Changelog nicht abrufbar: ${e.message}`;
    }
  }

  result.push({ name: img.name, repo: img.repo, tag: img.tag, github: img.github, latestTag, newerVersion: img.newerVersion, notes });
}

const promptParts = result.map(r =>
  `## ${r.name} (${r.repo}:${r.tag})\nNeuste Version: ${r.latestTag}\n\n${r.notes}`
).join('\n\n════════════\n\n');

const prompt = `Du bist ein IT-Administrator-Assistent.
Folgende Docker-Images haben Updates erhalten. Fasse für jeden die wichtigsten Änderungen in 2–3 Sätzen zusammen.
Bewerte kurz ob ein Update dringend (Sicherheitslücke), empfohlen (wichtige Fixes) oder optional (neue Features) ist.
Weise explizit auf Breaking Changes hin falls vorhanden.
Schreibe auf Deutsch, ohne Markdown-Formatierung, keine Codeblöcke.

${promptParts}

/no_think`;

return [{ json: { updates: result, prompt } }];

const kiRaw = $('KI Zusammenfassung').first().json;
const parsed = typeof kiRaw === 'string' ? JSON.parse(kiRaw) : kiRaw;
const body = typeof parsed.body === 'string' ? JSON.parse(parsed.body) : (parsed.body || parsed);
let zusammenfassung = body?.choices?.[0]?.message?.content?.trim() || '';
zusammenfassung = zusammenfassung.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
if (!zusammenfassung) zusammenfassung = '(Keine KI-Zusammenfassung verfügbar)';
const updates = $('Changelogs laden').first().json.updates;
return [{ json: { zusammenfassung, updates } }];

function mdToHtml(md) {
  const esc = s => s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const inline = s => esc(s).replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>').replace(/\*(.+?)\*/g, '<em>$1</em>');
  const lines = md.split('\n');
  let html = '';
  let inList = false;
  const closeList = () => { if (inList) { html += '</ul>'; inList = false; } };
  for (let line of lines) {
    line = line.trim();
    if (!line) { continue; }
    if (/^-{3,}$/.test(line)) { closeList(); html += '<hr style="border:none;border-top:1px solid #e5e7eb;margin:14px 0;">'; continue; }
    let m;
    if ((m = /^#{2,4}\s+(.*)$/.exec(line))) {
      closeList();
      html += `<h3 style="font-size:14px;color:#1E3A8A;margin:14px 0 6px;">${inline(m[1])}</h3>`;
      continue;
    }
    if ((m = /^[-*]\s+(.*)$/.exec(line))) {
      if (!inList) { html += '<ul style="margin:4px 0 8px;padding-left:20px;">'; inList = true; }
      html += `<li style="font-size:13px;color:#374151;margin-bottom:4px;">${inline(m[1])}</li>`;
      continue;
    }
    closeList();
    html += `<p style="margin:0 0 8px;font-size:13px;color:#374151;">${inline(line)}</p>`;
  }
  closeList();
  return html;
}

const { zusammenfassung, updates } = $input.first().json;
const datum = new Date().toLocaleDateString('de-DE', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const th = (t) => `<th style="padding:8px 12px;background:#1E3A8A;color:#fff;font-size:12px;font-weight:600;text-align:left;">${t}</th>`;
const td = (t, bg='#fff') => `<td style="padding:7px 12px;font-size:13px;border-bottom:1px solid #e5e7eb;background:${bg};">${t}</td>`;

const rows = updates.map((u, i) => {
  const bg = i % 2 === 0 ? '#fff' : '#f8fafc';
  return `<tr>
    ${td(`<strong>${u.name}</strong>`, bg)}
    ${td(`${u.repo}:${u.tag}`, bg)}
    ${td(u.newerVersion || u.latestTag || '–', bg)}
  </tr>`;
}).join('');

const table = `
<table style="width:100%;border-collapse:collapse;border-radius:8px;overflow:hidden;margin-bottom:20px;">
  <thead><tr>${th('Service')}${th('Image')}${th('Neue Version')}</tr></thead>
  <tbody>${rows}</tbody>
</table>`;

const summaryHtml = mdToHtml(zusammenfassung);

const html = `
<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;color:#0e0f0f;">

  <div style="background:linear-gradient(135deg,#1E3A8A,#2B9CD8);padding:24px 28px;border-radius:10px 10px 0 0;">
    <h1 style="margin:0;color:#fff;font-size:20px;">🐳 Docker Update-Bericht</h1>
    <p style="margin:6px 0 0;color:rgba(255,255,255,0.85);font-size:13px;">${datum} – ${updates.length} Update(s) verfügbar</p>
  </div>

  <div style="background:#fff;padding:24px 28px;border:1px solid #e5e7eb;border-top:none;">

    <h2 style="font-size:15px;color:#1E3A8A;border-bottom:2px solid #bfdbfe;padding-bottom:6px;margin:0 0 12px;">Verfügbare Updates</h2>
    ${table}

    <h2 style="font-size:15px;color:#1E3A8A;border-bottom:2px solid #bfdbfe;padding-bottom:6px;margin:20px 0 12px;">Was ist neu?</h2>
    <div style="background:#f8fafc;border-left:4px solid #2B9CD8;padding:14px 16px;border-radius:4px;">
      ${summaryHtml}
    </div>

    <div style="margin-top:20px;background:#fef9c3;border:1px solid #fde047;border-radius:8px;padding:12px 16px;">
      <p style="margin:0;font-size:12px;color:#713f12;"><strong>Hinweis:</strong> Updates bitte manuell durchführen und vorher testen. Nach dem Pull: <code>docker compose up -d [service]</code></p>
    </div>

  </div>

  <div style="background:#f8fafc;padding:12px 28px;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 10px 10px;font-size:11px;color:#9ca3af;text-align:center;">
    FreiKI · Automatisch generiert
  </div>

</div>`;

return [{ json: { html, subject: `🐳 ${updates.length} Docker-Update(s) verfügbar – ${datum}` } }];
